<template>

	<view class="accountPage">
		<!-- <view class="container">
			<view class="actionbar">
				{{title}}
			</view>
		</view> -->
		<view class="list">
			<view class="label" v-if="type == 'company'">
				请输入昵称
			</view>
			<view class="company" v-if="type == 'company'">
				
				<u-input v-model="user.company"  :height="100" :custom-style="{
								fontSize:'32rpx',
								
								
							}" />
			</view>
			<view class="label" v-if="type == 'email'">
				请输入邮箱
			</view>
			<view class="email" v-if="type == 'email'">
				<u-input v-model="user.email"  :height="100" :custom-style="{
								fontSize:'32rpx',
								
								
							}" />
			</view>
			<view class="label" v-if="type == 'qq'">
				请输入QQ号
			</view>
			<view class="qq" v-if="type == 'qq'">
				<u-input v-model="user.qq" :height="100" :custom-style="{
								fontSize:'32rpx',
								
								
							}" />
			</view>
			<view class="label" v-if="type == 'password'">
				请输入原密码
			</view>
			<view class="password" v-if="type == 'password' && code == ''" >
				<u-input v-model="user.old_password" placeholder="原密码" type="password" :height="100" :custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			<view class="label" v-if="type == 'password'" style="margin-top:10rpx;">
				请输入新登录密码
			</view>
			<view class="password" v-if="type == 'password'" >
				<u-input v-model="user.password" placeholder="新登录密码" type="password" :height="100" :custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			<view class="label" v-if="type == 'password'"  style="margin-top:10rpx;">
				请再次输入新登录密码
			</view>
			<view class="password" v-if="type == 'password'" >
				<u-input v-model="user.again_password" placeholder="再次输入" type="password" :height="100" :custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			
			
			<view class="label" v-if="type == 'trader_password'" >
				请输入原支付密码
			</view>
			<view class="trader_password" v-if="type == 'trader_password' && code == ''">
				<u-input v-model="user.old_trader_password" placeholder="原支付密码" type="password" :height="100"
					:custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			<view class="label" v-if="type == 'trader_password'"  style="margin-top:10rpx;">
				请输入新支付密码
			</view>
			<view class="trader_password" v-if="type == 'trader_password'">
				<u-input v-model="user.trader_password" placeholder="新支付密码" type="password" :height="100" :custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			<view class="label" v-if="type == 'trader_password'"  style="margin-top:10rpx;">
				请再次输入新登录密码
			</view>
			<view class="trader_password" v-if="type == 'trader_password'">
				<u-input v-model="user.again_trader_password" placeholder="再次输入" type="password" :height="100"
					:custom-style="{
															fontSize:'32rpx',
															
															
														}" />
			</view>
			
			
			<view class="btn submit" @click="save" v-if="">
				提交
			</view>
			<!-- <view class="exit-panel">
				<view class="btn" @click="save">
					提交
				</view>
			</view> -->
		</view>
	</view>

</template>

<script>
	export default {
		data() {
			return {
				list: [],
				title: '',
				type: '',
				code: '',

				user: {
					company: '',
					qq: '',
					email: '',
					password: '',
					old_password: '',
					again_password: '',
					trader_password: '',
					old_trader_password: '',
					again_trader_password: '',
					bind_qq:'',
				}
			}
		},
		onLoad(e) {
			this.type = e.type
			switch (e.type) {
				case 'company':
					this.title = '修改昵称'
					this.user.company = this.userinfo.company
					break;
				case 'qq':
					this.title = '修改QQ'
					this.user.qq = this.userinfo.qq
					break;
				case 'wx':
					this.title = '修改微信号'

					break;
				case 'email':
					this.title = '修改邮箱'
					this.user.email = this.userinfo.email
					break;
				case 'password':
					this.title = '修改登录密码'
					break;
				case 'trader_password':
					this.title = '修改支付密码'
					break;

			}

			if (e.code) {
				this.code = e.code
			}



			uni.setNavigationBarTitle({
				title: this.title
			})



		},
		methods: {
			loadData() {
				this.$u.api.ucenterset({})
					.then(res => {
						this.list = res
					}).catch(res => {})
			},
			checkFrom() {
				switch (this.type) {
					case 'company':

						break;
					case 'qq':

						this.$util.msg('请填写正确QQ号')
						return /^[1-9][0-9]{4,10}$/.test(this.user[this.type]);
						break;
					case 'wx':


						break;
					case 'email':
						this.$util.msg('请填写正确邮箱')
						return /[\w!#$%&'*+/=?^_`{|}~-]+(?:\.[\w!#$%&'*+/=?^_`{|}~-]+)*@(?:[\w](?:[\w-]*[\w])?\.)+[\w](?:[\w-]*[\w])?/
							.test(this.user[this.type]);
						break;

				}
				return true;
			},
			async save() {

				if (!this.user[this.type]) {
					this.$util.msg('请填写数据')
					return;
				}

				if (!this.checkFrom()) {
					return;
				}


				uni.showLoading({
					mask: true,
					title: '保存中...',

				})
				this.user.type = this.type
				this.user.code = this.code


				await this.$u.api.userinfosave(this.user)
					.then(res => {

						if (this.type == 'password' || this.type == 'trader_password') {


						} else {
							this.$u.vuex('userinfo.' + this.type, res.data);
						}

						this.$util.msg('保存成功')

						if (this.type == 'password' || this.type == 'trader_password') {

							if (this.code) {
								setTimeout(() => {
									//注册成功前往首页
									this.$util.back(3);
								}, 1500)
							} else {
								setTimeout(() => {
									//注册成功前往首页
									this.$util.back(2);
								}, 1500)
							}

						} else {
							setTimeout(() => {
								//注册成功前往首页
								this.$util.back();
							}, 1500)
						}

					}).catch(res => {})

				uni.hideLoading()
			}
		}
	}
</script>

